import React from 'react';
import InfoModal from './Modal';
import { scaleDown as Menu } from 'react-burger-menu'

class Slide extends React.Component {
  showSettings (event) {
    event.preventDefault();
  }

  constructor (props) {
    super(props)
    this.state = {
      menuOpen: false
    }
  }

  handleStateChange (state) {
    this.setState({menuOpen: state.isOpen})  
  }
  
  // This can be used to close the menu, e.g. when a user clicks a menu item
  closeMenu () {
    this.setState({menuOpen: false})
  }

  // This can be used to toggle the menu, e.g. when using a custom icon
  // Tip: You probably want to hide either/both default icons if using a custom icon
  // See https://github.com/negomi/react-burger-menu#custom-icons
  toggleMenu () {
    this.setState(state => ({menuOpen: !state.menuOpen}))
  }
  render () {
    return (
        <Menu isOpen={this.state.menuOpen}
        onStateChange={(state) => this.handleStateChange(state)}
        disableAutoFocus>
            <h1>메뉴</h1>
            <br></br>
            <a className="bm-menu-wrap" href="https://znznz6037.github.io/GANFaceChanger/">
                페이스 체인지
            </a>
    
            <a className="bm-item" href="/desserts">
                초상화
            </a>    
            <a className="menu-item" href="https://github.com/znznz6037/GANFaceChanger">
                GitHub
            </a>
            <a onClick={() => this.closeMenu()} className="menu-item" href="javascript:void(0)">
                <InfoModal/>
            </a>
      </Menu>
    );
  }
}

export default Slide